/**
 * Agent job execution record (job_token intentionally omitted)
 */
export type AgentJob = {
    /**
     * Timestamp when the job completed
     */
    completedAt?: Date;
    /**
     * ID of the agent config that ran this job (from the frozen snapshot)
     */
    configId?: number;
    /**
     * Name of the agent config that ran this job (from the frozen snapshot)
     */
    configName?: string;
    /**
     * Frozen agent config at submit time (an INSTANCE-scoped connection's baseUrl is redacted to scheme://host)
     */
    configSnapshot: unknown;
    /**
     * Docker container ID
     */
    containerId?: string;
    /**
     * Timestamp when the job was created
     */
    createdAt: Date;
    /**
     * Git provider comment/note ID for posted feedback
     */
    deliveryCommentId?: string;
    /**
     * Delivery status: null = not applicable, PENDING = awaiting delivery, DELIVERED = posted, FAILED = delivery error
     */
    deliveryStatus?: 'PENDING' | 'DELIVERED' | 'FAILED';
    /**
     * Human-readable error message
     */
    errorMessage?: string;
    /**
     * Container exit code
     */
    exitCode?: number;
    /**
     * Job ID
     */
    id: string;
    /**
     * Job type
     */
    jobType: 'PULL_REQUEST_REVIEW' | 'ISSUE_REVIEW' | 'CONVERSATION_REVIEW';
    /**
     * Tokens read from prompt cache
     */
    llmCacheReadTokens?: number;
    /**
     * Tokens written to prompt cache
     */
    llmCacheWriteTokens?: number;
    /**
     * Deprecated, always null (#1368 slice 6): the runner no longer reports cost. See the workspace's LLM usage rollup for the authoritative, catalog-derived per-job cost.
     */
    llmCostUsd?: number;
    /**
     * LLM model used (e.g. gpt-5.4-mini, claude-sonnet-4-5)
     */
    llmModel?: string;
    /**
     * Model version/snapshot date (e.g. 2026-03-17)
     */
    llmModelVersion?: string;
    /**
     * Total LLM API calls (steps) during execution
     */
    llmTotalCalls?: number;
    /**
     * Total input tokens consumed
     */
    llmTotalInputTokens?: number;
    /**
     * Total output tokens generated
     */
    llmTotalOutputTokens?: number;
    /**
     * Total reasoning/thinking tokens
     */
    llmTotalReasoningTokens?: number;
    /**
     * Job metadata (routing/display info)
     */
    metadata?: unknown;
    /**
     * Job output (agent results)
     */
    output?: unknown;
    /**
     * Number of retry attempts
     */
    retryCount: number;
    /**
     * Timestamp when the job started running
     */
    startedAt?: Date;
    /**
     * Current job status
     */
    status: 'QUEUED' | 'RUNNING' | 'COMPLETED' | 'FAILED' | 'TIMED_OUT' | 'CANCELLED';
};

/**
 * Live state of the API token behind the workspace's Outline connection
 */
export type OutlineTokenStatus = {
    /**
     * Whether Outline still accepts the stored token. False means revoked, expired or rejected.
     */
    accepted: boolean;
    /**
     * When the token lapses. Absent for a key created without an expiry.
     */
    expiresAt?: Date;
    /**
     * Last four characters of the token, as Outline reports them
     */
    last4?: string;
    /**
     * When Outline last saw the token used
     */
    lastActiveAt?: Date;
    /**
     * The token's name in Outline. Absent when the token cannot list its own key (a scoped key, or one owned by a user who cannot see it) — sync is unaffected.
     */
    name?: string;
};

/**
 * An Outline collection the token can see, offered in the add-collection picker
 */
export type OutlineCollectionCandidate = {
    /**
     * Whether this collection is already registered for mirroring
     */
    alreadyMirrored: boolean;
    /**
     * Outline collection id (UUID)
     */
    collectionId: string;
    /**
     * Collection color as configured in Outline
     */
    color?: string;
    /**
     * Collection description as shown in Outline
     */
    description?: string;
    /**
     * Collection icon as configured in Outline
     */
    icon?: string;
    /**
     * Collection name as shown in Outline
     */
    name?: string;
    /**
     * Outline url id (the short slug in collection URLs)
     */
    urlId?: string;
};

/**
 * A mirrored Outline collection with its sync state and live document count
 */
export type OutlineCollection = {
    /**
     * Outline collection id (UUID; the natural key)
     */
    collectionId: string;
    /**
     * Collection color as configured in Outline
     */
    color?: string;
    /**
     * When the collection was registered for mirroring
     */
    createdAt: Date;
    /**
     * Collection description as shown in Outline
     */
    description?: string;
    /**
     * Live (non-tombstoned) mirrored document count
     */
    documentCount: number;
    /**
     * Documents upstream reported for this collection at the last enumeration (coverage denominator)
     */
    documentsUpstream?: number;
    /**
     * Exports the last pass skipped because the shared budget ran out (0 on a clean pass)
     */
    exportsSkippedForBudget?: number;
    /**
     * Collection icon as configured in Outline
     */
    icon?: string;
    /**
     * Internal registry row id
     */
    id: number;
    /**
     * Last sync failure for this collection, cleared on the next clean pass
     */
    lastSyncError?: string;
    /**
     * When this collection last completed a full reconcile pass, if any
     */
    lastSyncedAt?: Date;
    /**
     * Collection name as shown in Outline, if known
     */
    name?: string;
    /**
     * Mirror lifecycle state (PAUSED freezes sync but keeps documents)
     */
    state: 'ENABLED' | 'PAUSED';
    /**
     * Whether a clean full pass has completed since registration or the last resume
     */
    syncStatus: 'PENDING' | 'COMPLETE';
    /**
     * Outline url id (the short slug in collection URLs)
     */
    urlId?: string;
};

/**
 * Full practice observation detail including guidance and evidence
 */
export type ObservationDetail = {
    /**
     * Artifact entity ID
     */
    artifactId: number;
    /**
     * Artifact type (e.g. PULL_REQUEST)
     */
    artifactType: 'PULL_REQUEST' | 'ISSUE' | 'CONVERSATION_THREAD';
    /**
     * Assessment: GOOD or BAD (null when NOT_APPLICABLE)
     */
    assessment?: 'GOOD' | 'BAD';
    /**
     * AI confidence score (0.0–1.0)
     */
    confidence: number;
    /**
     * Structured evidence: {"locations":[{"path","startLine","endLine"}], "snippets":[...], "references":[...]}
     */
    evidence?: {
        [key: string]: unknown;
    };
    /**
     * What to do — the delivered feedback for this observation (null if nothing was delivered)
     */
    guidance?: string;
    /**
     * Observation ID
     */
    id: string;
    /**
     * When the observation was made
     */
    observedAt: Date;
    /**
     * Practice name
     */
    practiceName: string;
    /**
     * Practice slug
     */
    practiceSlug: string;
    /**
     * Presence: PRESENT, ABSENT, or NOT_APPLICABLE
     */
    presence: 'PRESENT' | 'ABSENT' | 'NOT_APPLICABLE';
    /**
     * AI reasoning behind the observation
     */
    reasoning?: string;
    /**
     * Severity level (null unless assessment is BAD)
     */
    severity?: 'CRITICAL' | 'MAJOR' | 'MINOR' | 'INFO';
    /**
     * Observation title
     */
    title: string;
};

